  function cancelEdit() { setEditInv(null); setEditFields({}); }

  function getProgramAvailableBalance(programId) {
    var prog = FUNDING_PROGRAMS_DB.find(function(p) { return p.id === programId; });
    if (!prog) return 0;
    var progInvs = viewData.invoices.filter(function(inv) { return inv.fundingProgram === programId; });
    var fundedBalance = 0;
    progInvs.forEach(function(inv) {
      if (inv.fundingStatus === "pending" || inv.fundingStatus === "approved") return;
      fundedBalance += inv.capitalDue || 0;
    });
    var funderInflows = 0, totalDisbursed = 0, pendingDisbursalsAmt = 0;
    if (prog.fundFlows) prog.fundFlows.forEach(function(ff) { if (ff.type === "inflow") funderInflows += ff.amount; else if (ff.status === "Pending") pendingDisbursalsAmt += ff.amount; else totalDisbursed += ff.amount; });
    var progInvIdSet = {};
    progInvs.forEach(function(inv) { progInvIdSet[inv.id] = true; });
    SUPPLIER_PAYMENT_QUEUE.forEach(function(spq) {
      if (spq.status === "Pending" && spq.sourceInvoiceId && progInvIdSet[spq.sourceInvoiceId]) {
        pendingDisbursalsAmt += spq.amount || 0;
      }
    });
    var buyerReceipts = 0, totalHoldbackDisbursed = 0;
    progInvs.forEach(function(inv) {
      if (inv.payments) inv.payments.forEach(function(p) {
        buyerReceipts += (p.appliedToPenalty || 0) + (p.appliedToInterest || 0) + (p.appliedToCapital || 0) + (p.appliedToHoldback || 0);
      });
      totalHoldbackDisbursed += inv.holdbackDisbursed || 0;
    });
    var totalInflows = r2(funderInflows + buyerReceipts);
    var totalFundsOut = r2(totalDisbursed + fundedBalance + totalHoldbackDisbursed);
    return r2(totalInflows - totalFundsOut - pendingDisbursalsAmt);
  }

  function fundInvoice(invId, programId) {
    var raw = INVOICES_DB.find(function(x) { return x.id === invId; });
    if (!raw || raw.fundingStatus !== "pending") return;
    if (!programId) return;
    raw.fundingStatus = "approved";
    raw.approvedDate = viewDate;
    raw.fundingProgram = programId;
    var prog = FUNDING_PROGRAMS_DB.find(function(p) { return p.id === programId; });
    var progName = prog ? prog.name : programId;
    auditLog("Invoice Approved", invId + " approved for funding via " + progName + ": " + money(raw.amount, raw.currency) + " — capital " + money(raw.capitalDue, raw.currency) + " to " + raw.supplierName, { invoiceId: invId, amount: raw.amount, currency: raw.currency, capitalDue: raw.capitalDue, supplierId: raw.supplierId, supplierName: raw.supplierName, supplier: raw.supplierName, buyerId: raw.buyerId, buyer: raw.buyerName, approvedDate: raw.approvedDate, fundingProgram: programId, fundingProgramName: progName });
    setDataVer(function(v) { return v + 1; });
  }

  function executeFunding(invId) {
    var raw = INVOICES_DB.find(function(x) { return x.id === invId; });
    if (!raw || raw.fundingStatus !== "approved") return;
    raw.fundingStatus = "funded";
    raw.fundedDate = viewDate;
    var prog = FUNDING_PROGRAMS_DB.find(function(p) { return p.id === raw.fundingProgram; });
    if (prog) prog.currentFundedBalance = r2((prog.currentFundedBalance || 0) + raw.capitalDue);
    var progName = prog ? prog.name : raw.fundingProgram;
    var supplier = getSupplierById(raw.supplierId) || getParentSupplier(raw.supplierName);
    var bankInfo = getSupplierBankDetails(raw.supplierId || raw.supplierName, raw.fundingProgram);
    var now = new Date();
    var useDisplay = viewDate !== REF_DATE ? new Date(viewDate + "T12:00:00").toLocaleString("en-GB", { day: "2-digit", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false }) + " (as of)" : now.toLocaleString("en-GB", { day: "2-digit", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false });
    var cpId = "CPQ-" + String(SUPPLIER_PAYMENT_QUEUE.length + 1).padStart(7, "0");
    SUPPLIER_PAYMENT_QUEUE.push({
      id: cpId, type: "funding", invoiceId: invId, invoiceIds: [invId],
      supplierName: raw.supplierName, supplierId: raw.supplierId || (supplier ? supplier.id : ""),
      bankName: bankInfo.bankName, bankDetails: bankInfo.bankDetails, bankVerified: bankInfo.bankVerified,
      amount: raw.capitalDue, currency: raw.currency, status: "Completed",
      programId: raw.fundingProgram, programName: progName,
      createdDisplay: useDisplay,
      executedAt: now.toISOString(),
      executedDisplay: useDisplay
    });
    auditLog("Invoice Funded", invId + " funded via " + progName + ": capital " + money(raw.capitalDue, raw.currency) + " advanced to " + raw.supplierName + " (" + cpId + ") — " + (bankInfo.bankName ? bankInfo.bankName + " " + bankInfo.bankDetails : "No bank on file"), { invoiceId: invId, amount: raw.amount, currency: raw.currency, capitalDue: raw.capitalDue, supplierId: raw.supplierId, supplier: raw.supplierName, buyerId: raw.buyerId, buyer: raw.buyerName, fundedDate: raw.fundedDate, fundingProgram: raw.fundingProgram, fundingProgramName: progName, completedPaymentId: cpId, bankName: bankInfo.bankName, bankDetails: bankInfo.bankDetails, bankVerified: bankInfo.bankVerified });
    setDataVer(function(v) { return v + 1; });
  }

  function cancelApproval(invId) {
    var raw = INVOICES_DB.find(function(x) { return x.id === invId; });
    if (!raw || raw.fundingStatus !== "approved") return;
    var oldProg = raw.fundingProgram;
    var progName = "";
    if (oldProg) { var fp = FUNDING_PROGRAMS_DB.find(function(p) { return p.id === oldProg; }); if (fp) progName = fp.name; }
    raw.fundingStatus = "pending";
    raw.fundingProgram = null;
    raw.approvedDate = null;
    // Remove any associated payment queue entries for this invoice
    var removed = [];
    for (var qi = SUPPLIER_PAYMENT_QUEUE.length - 1; qi >= 0; qi--) {
      if (SUPPLIER_PAYMENT_QUEUE[qi].invoiceId === invId && SUPPLIER_PAYMENT_QUEUE[qi].type === "funding") {
        removed.push(SUPPLIER_PAYMENT_QUEUE[qi].id);
        SUPPLIER_PAYMENT_QUEUE.splice(qi, 1);
      }
    }
    auditLog("Invoice Approval Cancelled", invId + " rejected for funding" + (progName ? " from " + progName : "") + ", returned to funding queue" + (removed.length > 0 ? " (removed queue: " + removed.join(", ") + ")" : ""), { invoiceId: invId, amount: raw.amount, currency: raw.currency, supplierId: raw.supplierId, supplierName: raw.supplierName, supplier: raw.supplierName, buyerId: raw.buyerId, buyer: raw.buyerName, previousProgram: oldProg, previousProgramName: progName, removedQueueEntries: removed });
    setDataVer(function(v) { return v + 1; });
  }

  function executeAdjustment(invId, type) {
    var raw = INVOICES_DB.find(function(x) { return x.id === invId; });
    if (!raw) return;
    var pen = r2(parseFloat(adjPenalty) || 0);
    var int2 = r2(parseFloat(adjInterest) || 0);
    var cap = r2(parseFloat(adjCapital) || 0);
    if (pen <= 0 && int2 <= 0 && cap <= 0) return;
    var total = r2(pen + int2 + cap);
    if (!raw.adjustments) raw.adjustments = [];
    var now = new Date();
    raw.adjustments.push({
      type: type, date: now.toISOString().split("T")[0], timestamp: now.toISOString(),
      display: now.toLocaleString("en-GB", { day: "2-digit", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false }),
      penalty: pen, interest: int2, capital: cap, total: total
    });
    var label = type === "credit" ? "Credit Adjustment" : "Debit Adjustment";
    auditLog(label, invId + " " + label.toLowerCase() + ": Pen " + money(pen, raw.currency) + ", Int " + money(int2, raw.currency) + ", Cap " + money(cap, raw.currency) + " (Total: " + money(total, raw.currency) + ")", { invoiceId: invId, adjustmentType: type, penalty: pen, interest: int2, capital: cap, total: total, currency: raw.currency });
    setAdjInv(null); setAdjType(""); setAdjPenalty(""); setAdjInterest(""); setAdjCapital("");
    setDataVer(function(v) { return v + 1; });
  }

